-- Poland – EU Blue Card / Skilled Worker Residence — 30 FAQs
UPDATE public.service_library
SET academy_metadata = jsonb_set(
  COALESCE(academy_metadata, '{}'::jsonb),
  '{faqs}',
  '[{"q":"Can we guarantee Opportunity Card approval?","a":"No. Embassy assesses points and documentation. Never promise approval."},{"q":"How to calculate points?","a":"Use official criteria on www.gov.pl—qualification, experience, language, age, prior Poland stay."},{"q":"Need job offer?","a":"No—that is the purpose. Search for job after arrival. Blocked account required instead."},{"q":"Can work on Opportunity Card?","a":"Limited—part-time work while searching allowed per current rules. Verify limits."},{"q":"Difference from job seeker visa?","a":"Opportunity Card replaces old job seeker for points-based pathway—verify current rules."},{"q":"Blocked account amount?","a":"Verify current amount on embassy website—similar to student blocked account."},{"q":"After finding job?","a":"Apply for work residence permit at Ausländerbehörde."},{"q":"Age limit?","a":"No strict limit but fewer age points above 35."},{"q":"What is Description for this service?","a":"Residence permit for qualified professionals to search for employment in Poland for up to one year without prior job offer. Points-based eligibility under Section 20a AufenthG."},{"q":"What is Eligible applicants for this service?","a":"Minimum 6 points · Recognised qualification or IT experience · Polish A1 or English B2 · Blocked account or employment contract · Age typically under 35 for max age points"},{"q":"What is Points system for this service?","a":"Points for qualification recognition, work experience, language, age, and previous Poland stay. Minimum 6 points required."},{"q":"Important note on Points system?","a":"Points for qualification recognition, work experience, language, age, and previous Poland stay. Minimum 6 points required."},{"q":"What is Key authority for this service?","a":"Poland Embassy in India · Local Ausländerbehörde after arrival"},{"q":"What is After approval for this service?","a":"Enter Poland; search for qualified employment; convert to work residence permit when job secured."},{"q":"Is Minimum 6 points achieved required?","a":"Calculate using official criteria"},{"q":"Is Recognised degree or IT experience pathway required?","a":"Recognised degree or IT experience pathway is typically required."},{"q":"Is Polish A1 or English B2 required?","a":"Polish A1 or English B2 is typically required."},{"q":"Is Blocked account or job offer required?","a":"Financial proof required"},{"q":"Is Qualification recognition (if claiming points) required?","a":"Anabin or partial recognition"},{"q":"Is Valid passport required?","a":"Valid passport is typically required."},{"q":"Is Health insurance required?","a":"Assess whether Health insurance is satisfied for this case."},{"q":"What is the Processing time?","a":"8–12w — Embassy processing"},{"q":"What is the Government fee?","a":"€75 — National visa approx"},{"q":"What is the Our approval rate?","a":"82% — ~70% benchmark"},{"q":"What is the Required docs?","a":"14 — + points evidence"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt & blocked account"},{"q":"What if the client has Below 6 points?","a":"Calculate points honestly; improve language or get recognition"},{"q":"Why is Below 6 points a problem?","a":"Application lodged without meeting minimum points."},{"q":"What if the client has Qualification not recognised?","a":"Check Anabin database; apply for recognition if needed"},{"q":"Why is Qualification not recognised a problem?","a":"Degree not equivalent to Polish qualification for points."}]'::jsonb
), updated_at = now()
WHERE id = 'b2000001-0001-4000-8000-0000000000df'::uuid;
